// Initializing Channel and populating with Content
// 

//
//
// Hermes Object
// - Initial Load for channel
// - Refresh of channel
// - Message template
// 
//
var hermes = {
	message: {},

	loadChannel: function( id ) {
		$.ajax({
			url: '/hermes/channel/'+ id +'/load',
			type: "GET",
			dataType: "json",
			async: true,
			success: function (data)
			{
				console.log( 'is owner: ' + data.isOwner );
				channelWrapper = $('[data-source="'+ id +'"]'); 
				channelMessagesWrapper = channelWrapper.children('.hermes-channel-messages-wrapper');
				channelMessagesWrapper.html('');
				channelMessagesWrapper.children('.loader').hide();
				channelWrapper.children('.hermes-message-form').attr('data-target', id )
				$('.hermes-channel-title').html( data.name );
				if ( data.isOwner == true ) {
					$('.hermes-channel-title').prepend('<div class="pull-right"><a href="'+ data.deleteUrl +'" class="text-danger confirmation tooltipster hermes-channel-delete" data-id="'+ id +'" title="This will delete the conversation for both participants." href=""><small>Delete Conversation</small></a></div>')
					bindtooltipster();
				}
				data.messages.forEach(function( message ) {
					if ( message.content ) {
						messageBlock = hermes.renderMessage( message );
						channelMessagesWrapper.append( messageBlock );
						channelMessagesWrapper.scrollTop(channelMessagesWrapper[0].scrollHeight);
					}
				});
				channelWrapper.find('.hermes-channel').val( data.channelId );
			}
		}); 
	},
	refreshChannel: function( channel, timestamp ) {
		console.log('REFCHAN001');
		refreshUrl = '/hermes/channel/refresh';
		$.ajax({
			url: refreshUrl,
			type: "GET",
			dataType: "json",
	        data: {
	            "timestamp": timestamp,
	            "channel": channel,
	        },
			async: true,
			success: function (data)
			{
				data.messages.forEach(function( message ) {
					// Making sure that duplicates due to latency will not be shown.
			        if( !$("#message-"+ message.id ).length){
			        	// Creating Message
						messageBlock = hermes.renderMessage( message );
						// Appending Message
						channelMessagesWrapper.append( messageBlock );
						// Navigating to the bottom of the div 
						channelMessagesWrapper.animate({ scrollTop: channelMessagesWrapper.prop("scrollHeight")}, 500);
			        }
				});
			}
		}); 
	},
	renderMessage: function( message ) {
        time = convertTimestamp( message.timestamp  );
        if ( message.slug ) {
        	var urlPart1 = `<a class="float-left bl" href="`+ message.slug +`">`;
        	var urlPart2 = `</a>`
        } else {
        	var urlPart1 = ``;
        	var urlPart2 = ``;
        }

        if ( message.avatar ) {
        	var image = urlPart1 +`<img src="`+ message.avatar +`" class="img-fluid rounded-circle float-left" />`+ urlPart2 ;
        } else {
        	var image = '';
        }


		messageBlock = `
			<div id="message-`+ message.id+`"class="hermes-message chat-element">
				`+ image +`
				<div class="hermes-message-content-wrapper media-body">
					`+ urlPart1 +`<strong>`+ message.persona +`</strong>`+ urlPart2 +` <small class="text-muted">`+ time +`</small>
					<p class="m-b-xs hermes-message-content">`+ message.content +`</p>
				</div>
			</div>
		`;
		return messageBlock;
	}
};


