String.prototype.nl2br = function()
{
    return this.replace(/\n/g, "<br />");
}



function getURLParameter(sParam)
{
    var sPageURL = window.location.search.substring(1);
    var sURLVariables = sPageURL.split('&');
    for (var i = 0; i < sURLVariables.length; i++)
    {
        var sParameterName = sURLVariables[i].split('=');
        if (sParameterName[0] == sParam)
        {
            return sParameterName[1];
        }
    }
}


// Mention System

function bindmention() {
	$('.hermes-message, .log-message, .comment-message').suggest('@', {
		data:  function(q, provide) {
			console.log('fetching data');
			that = this;
			if (q) {
				return $.getJSON("/hermes/suggest", { q: q });
			}
		},
		map: function(user) {

			console.log( user );

			return {
			  value: user.slug,
			  text: '<strong>'+user.fullname+'</strong> <small> by '+ user.player +'</small>'
			}

			if (timeout) {
				clearTimeout(timeout);
				timeout = null;
			}

			timeout = setTimeout(processData, 500);
		}
	});
}

