$(document).ready(function() {
    // 
    // MESSAGE CENTER - Left sidebar
    // Load Latest Active Channels List
    // 
    if ( $('#hermes-channels').length ) 
    {
        console.log('REFCHAN002');
        $.ajax({
            url: $('#hermes-channels').attr('data-source'),
            type: "GET",
            dataType: "json",
            async: true,
            success: function (data)
            {
              if ( data ) {
                  var i = 1;
                  $('#hermes-channels-loader').addClass('d-none');

                  data.forEach(function(element) {
                      if ( element && element.link.length )
                      {

                          if ( i == 1 ) {
                              if ( $('.hermes-channel-message-center').length )
                              {
                                  if ( getURLParameter('id') ) {
                                      var id = getURLParameter('id') 
                                      hermes.loadChannel( id );
                                      $('.hermes-channel-message-center').attr('data-source', id );
                                  } else {
                                      $('.hermes-channel-message-center').attr('data-source', element.id );
                                      hermes.loadChannel( element.id );
                                  }
                              } 
                              i = 0;
                          }
                          highlightClass = '';
                          if ( element.highlight == 1 ) {
                              highlightClass = 'highlight-channel';
                          }
                          
                          time = convertTimestamp( element.last_update );

                          $('#hermes-channels').append('<li class="channel '+ highlightClass +'"><a href="'+ element.link +'" data-id="'+ element.id +'"><strong>'+ element.name + '</strong><p class="m-0"><small><i class="far fa-clock"></i> '+ time +'</small></p></a></li>')
                      }
                  });

              }
            }
        }); 

        $(document).on('click', '#hermes-channels .channel a', function( event ){
            event.preventDefault();
            $('.hermes-channel-message-center').attr('data-source', $(this).attr('data-id') );
            hermes.loadChannel( $(this).attr('data-id') );
            $( this ).parent('li').removeClass('highlight-channel');            
        });

    }
  
    refreshMessagesCounter();

});




