function printTotalWeight( data ) {
    console.log('time to update the total weight');
    console.log( data );
    var totalWeight = 0;
    for (var key in data) {
        if (data.hasOwnProperty(key)) {
          console.log( totalWeight);

          weight = Number.parseFloat( data[key].weight ).toFixed(2);
          console.log( weight );

          console.log('Quantity: ' + data[key].quantity + ' Weight: ' + weight );

          itemsWeight = parseInt( data[key].quantity ) * weight;
          console.log('Total: ' + itemsWeight)
          totalWeight = totalWeight + itemsWeight;
        }
    }
    console.log('Total Weight: ' + totalWeight );
    $('#total-weight').html( totalWeight );
    return totalWeight;
}


