// File select
$(document).on('change', ':file', function() {
    var input = $(this),
        numFiles = input.get(0).files ? input.get(0).files.length : 1,
        label = input.val().replace(/\\/g, '/').replace(/.*\//, '');
    input.trigger('fileselect', [numFiles, label]);
});

$(':file').on('fileselect', function(event, numFiles, label) {
  var input = $(this).parents('.input-group').find(':text'),
      log = numFiles > 1 ? numFiles + ' files selected' : label;
      $("span.cover-image-filename").text( log.trimToLength(12) );
});


// Concentration Mode

$(document).on('click','.focus-mode-off', function( event ) {
    event.preventDefault();
    console.log('activating focus mode');
    $('.topbar').fadeOut('slow');
    $('.page-title').fadeOut('slow');
    $('.article-title-wrapper').fadeOut('slow');
    $('.page-title-box').fadeOut('slow');
    $('.wide-screen-panel').css('opacity','0.5');
    $('.article-main-wrapper').toggleClass('col-md-9 col-md-12')
    $('.article-sidebar-wrapper').toggleClass('col-md-3 col-md-6');
    $('.article-sidebar-wrapper').addClass('offset-md-3');
    $('.article-todo-wrapper').fadeOut('slow');
    $('.article-ancillary-wrapper').fadeOut('slow');
    $('.partners').fadeOut('slow');
    $('.footer').fadeOut('slow');
    $('.article-vignette').attr('rows',30);
    $('.article-vignette').css('font-size','1.5em');
    $('.article-vignette').css('line-height','1.55em');

    $('#contentbundle_prose_prose').attr('rows',30);
    $('#contentbundle_prose_prose').css('font-size','1.5em');
    $('#contentbundle_prose_prose').css('line-height','1.55em');
    $('.article-content-header').css('padding-top','0px');
    $('.vignette-container').toggleClass('article-solid-background');
    $('.content-container').toggleClass('content-article');


    $(this).toggleClass('focus-mode-off focus-mode-on');
    $(this).children('span').html('Disable Focus Mode');
    $('.content-page').addClass('focus-mode');
    $("body").toggleClass("mini-navbar");
    SmoothlyMenu();

});



$(document).on('click','.focus-mode-on', function( event ) {
    event.preventDefault();
    $('.topbar').fadeIn('slow');
    $('.page-title').fadeIn('slow');
    $('.article-title-wrapper').fadeIn('slow');
    $('.page-title-box').fadeIn('slow');
    $('.wide-screen-panel').css('opacity','1');
    $('.article-main-wrapper').toggleClass('col-md-9 col-md-12')
    $('.article-sidebar-wrapper').toggleClass('col-md-3 col-md-6');
    $('.article-sidebar-wrapper').removeClass('offset-md-3');
    $('.article-todo-wrapper').fadeIn('slow');
    $('.article-ancillary-wrapper').fadeIn('slow');
    $('.partners').fadeIn('slow');
    $('.footer').fadeIn('slow');
    $('.article-vignette').attr('rows',10);
    $('.article-vignette').css('font-size','15px');
    $('.article-vignette').css('line-height','18pt');
    $('.article-content-header').css('padding-top','200px');

    $('.vignette-container').toggleClass('article-solid-background');
    $('.content-container').toggleClass('content-article');
    $('#contentbundle_prose_prose').attr('rows',10);
    $('#contentbundle_prose_prose').css('font-size','15px');
    $('#contentbundle_prose_prose').css('line-height','18pt');
    
    $(this).toggleClass('focus-mode-off focus-mode-on')
    $(this).children('span').html('Enable Focus Mode');
    $('.content-page').removeClass('focus-mode');
    $("body").toggleClass("mini-navbar");
    SmoothlyMenu();

});



