$( document ).ready(function() {

	$( ".articleSelector" ).each(function( key, value ) {
		selectElement 			= $( this );
		selectElementId 		= selectElement.attr('id');
		selectElementName 		= selectElement.attr('name');
		selectElementTemplate 	= selectElement.attr('data-template');

		if( jQuery.type( selectElement.val() ) === "string" && selectElement.val().length > 0 || 
			!jQuery.type( selectElement.val() ) === "undefined" || 
			jQuery.type( selectElement.val() ) === "array" && !jQuery.isEmptyObject( selectElement.val()) ) {
			// Create Link
			$('#'+ selectElementId +' :selected').each(function(i, sel){ 
				that = $( this );
				selectOptionValue = that.val();
				selectOptionTitle = that.text()
			    $.ajax({
			        url: '/api/article/'+ selectOptionValue + '/edit-url',
			        type: "GET",
			        selectId: selectElementId,
			        optionTitle: selectOptionTitle,
			        dataType: "json",
			        async: true,
			        success: function (data)
			        {
			            if ( data ) {
	        				$('#'+ this.selectId ).parent().prepend('<div class="pull-right" id="'+ this.selectId +'_article_link">&nbsp&nbsp&nbsp<i class="fas fa-link"></i> <a target="_blank" href="'+ data.url +'">'+ this.optionTitle +'</a></div>');
	        			}
			        }
			    });
			});
		} else if ( !selectElement.hasClass('articleSelectorMultiple')  ) {
			// Create Articles
			selectElement
				.parent()
				.prepend('<div class="pull-right create-article-button-container">&nbsp&nbsp&nbsp<i class="fas fa-plus-square"></i> <a id="'+ selectElementId +'_article_create" class="createNewArticle"  data-name="'+ selectElementName +'" data-template="'+ selectElementTemplate +'" data-id="'+ selectElementId +'" href="#">Create new article and link it</a></div>');
		}
		if ( selectElement.hasClass('articleSelectorMultiple') ) {
			selectElement
				.parent()
				.prepend('<div class="pull-right create-article-button-container">&nbsp&nbsp&nbsp<i class="fas fa-plus-square"></i> <a id="'+ selectElementId +'_article_create" class="createNewArticle"  data-name="'+ selectElementName +'" data-template="'+ selectElementTemplate +'" data-id="'+ selectElementId +'" href="#">Create new article and link it</a></div>');
		}
	});

	function createTemplateOptionsSelect( name, template, selectElementId ) {
		var html = `<select class="form-control select2select select2 article-create-template" name="" id="" 
							data-name="`+ name +`" 
    						data-template="`+ template +`" 
    						data-id="`+ selectElementId +`" >`;
					
		if ( template == 'any' ) {
			html += `
				<option value="">Select Template</option>
				<option value="article">Article, Generic</option>
				<option value="ethnicity">Ethnicity</option>
				<option value="item">Item</option>
				<option value="language">Language</option>
				<option value="location">Geographic Location</option>
				<option value="settlement">Settlement</option>
				<option value="landmark">Building / Landmark</option>
				<option value="organization">Organization</option>
				<option value="person">Person</option>
				<option value="species">Species</option>
				<option value="technology">Technology</option>
				<option value="vehicle">Vehicle</option>
				<option value="law">Law</option>
				<option value="ritual">Ritual</option>
				<option value="plot">Plot / Quest</option>
				<option value="rank">Rank</option>
				<option value="condition">Condition</option>
				<option value="document">Document</option>
				<option value="spell">Spell</option>
				<option value="prose">Prose</option>
				<option value="militaryConflict">Military Conflict</option>
				<option value="formation">Military Formation</option>
				<option value="myth">Myth</option>
				<option value="profession">Profession</option>
				<option value="material">Material</option>
			`;
		} else if ( template = 'any-location' ){
			html += `
				<option value="location">Geographic Location</option>
				<option value="settlement">Settlement</option>
				<option value="landmark">Building / Landmark</option>
			`;		
		}

		html	+=	`</select>`;

		return html;
	}

	$(document).on('click', '.createNewArticle', function( event){
	    that = $(this);
	    selectElementId = that.attr('data-id');
	    template = that.parent().siblings('select').attr('data-template');
	    name = that.parent().siblings('select').attr('name');
	    that.parent().siblings('span.select2').remove();
	    that.parent().siblings('p').remove();

	    var htmlOutput = `<div class="article-create-form">
	    					<input type="text" name="article-create-title" id="article-create-title" placeholder="Article title" class="form-control article-create-title"/>`;
	    if ( template == 'any' || template == 'any-location' ) {
	    	var templateSelector = createTemplateOptionsSelect( name, template, selectElementId );
	    	htmlOutput += templateSelector;
	    } else {
	    	htmlOutput	+= `<input type="hidden" class="article-create-template" 
	    						data-name="`+ name +`" 
	    						data-template="`+ template +`" 
	    						data-id="`+ selectElementId +`" 
	    						value="`+ template +`" />`;
	    }

		htmlOutput	+= `<input class="article-create-button btn btn-primary" type="submit" value="Create & Link">
    					</div>`;

	    that.parent().parent().append( htmlOutput );
	    event.preventDefault();
	});

	$(document).on('click', '.article-create-button', function( event){
		that = $( this );
		title = that.siblings('.article-create-title').val();
		selectElementId = that.siblings('.article-create-template').attr('data-id');
		selectElementName = that.siblings('.article-create-template').attr('data-name');
		template = that.siblings('.article-create-template').val();
		// template = that.parent().siblings('.create-article-button-container').children('#'+ selectElementId +'_article_create' ).attr('data-template');

	    $.ajax({
	        url: '/api/article/create',
	        type: "GET",
	        selectId: selectElementId,
	        selectName: selectElementName,
	        data: {'title': title,'type': template },
	        dataType: "json",
	        formClass: that.parent(),
	        async: true,
	        success: function (data)
	        {	
	            if ( data ) {
					$('#'+ this.selectId +'_article_create' ).parent().parent().append('<h5>'+ title +'</h5>');

    				$('#'+ this.selectId ).append('<option selected="selected" value="'+ data +'">'+ title +'</option');

					if ( !$('#'+ this.selectId ).prop('multiple') ) {
						$( this.formClass ).siblings('.create-article-button-container').remove();
					}					
					$( this.formClass ).remove();
 
				    var dataString = '&title=' + title + '&template=' + template +'&importance=1';

				    $.ajax({
				        url: '/world/todo/new',
				        type: "GET",
				        data: dataString,
				        dataType: "json",
				        async: true,
				        success: function (data)
				        {
	    	  	          todoListRefresh();
				        }
				    });
				}
	        }
	    });
	    event.preventDefault();
	});
});